import React from 'react';

interface MatchCardProps {
    match: {
        redAlliance: { teamNumber: number; opr: number }[];
        blueAlliance: { teamNumber: number; opr: number }[];
        matchNumber: number;
    };
}

const MatchCard: React.FC<MatchCardProps> = ({ match }) => {
    const calculateTotalOpr = (alliance: { teamNumber: number; opr: number }[]) => {
        return alliance.reduce((total, team) => total + team.opr, 0);
    };

    const redAllianceOpr = calculateTotalOpr(match.redAlliance);
    const blueAllianceOpr = calculateTotalOpr(match.blueAlliance);
    const predictedWinner = redAllianceOpr > blueAllianceOpr ? 'Red Alliance' : 'Blue Alliance';

    return (
        <div className="match-card">
            <h3>Match {match.matchNumber}</h3>
            <div className="alliance">
                <h4>Red Alliance</h4>
                <ul>
                    {match.redAlliance.map(team => (
                        <li key={team.teamNumber}>Team {team.teamNumber} - OPR: {team.opr}</li>
                    ))}
                </ul>
                <p>Total OPR: {redAllianceOpr}</p>
            </div>
            <div className="alliance">
                <h4>Blue Alliance</h4>
                <ul>
                    {match.blueAlliance.map(team => (
                        <li key={team.teamNumber}>Team {team.teamNumber} - OPR: {team.opr}</li>
                    ))}
                </ul>
                <p>Total OPR: {blueAllianceOpr}</p>
            </div>
            <h4>Predicted Winner: {predictedWinner}</h4>
        </div>
    );
};

export default MatchCard;
